def lcm(a, b):
    return a * b // gcd(a, b)

def sum_of_gcds(n, k):
    def gcd_sum(n):
        return sum(gcd(i, n) for i in range(1, n+1))

    total_gcd_sum = 0
    factors = [n[i] for i in range(k)]

    while True:
        current_gcd = reduce(gcd, factors)
        if current_gcd == 1:
            break

        count = 1
        for i in range(k):
            count *= factors[i] // current_gcd

        total_gcd_sum += current_gcd * count
        total_gcd_sum %= MOD

        for i in range(k):
            if factors[i] % current_gcd == 0:
                factors[i] //= current_gcd

    return total_gcd_sum

