from functools import reduce

MOD = 10**9 + 7

def lcm(a, b):
    return a * b // gcd(a, b)

def sum_of_gcds(n, k):
    def gcd_sum(n):
        if n == 1:
            return 1
        else:
            return (n * (n + 1)) // 2

    total_sum = 0
    for d in range(1, n + 1):
        count = 0
        for i in range(d, n + 1, d):
            count += n // i
        total_sum += d * count
    return total_sum % MOD

def main():
    input = sys.stdin.read
    data = input().split()

    index = 0
    T = int(data[index])
    index += 1

    results = []
    for _ in range(T):
        K = int(data[index])
        index += 1
        dimensions = list(map(int, data[index:index+K]))
        index += K

        result = 1
        for dim in dimensions:
            result = (result * sum_of_gcds(dim, K)) % MOD

        results.append(result)

    for result in results:
        print(result)

