from collections import defaultdict

input = sys.stdin.read
data = input().split()

n = int(data[0])
k = int(data[1])

pebbles = list(map(int, data[2:]))

def can_paint(pebbles, k):
    max_pebbles = max(pebbles)
    if max_pebbles > k:
        return False

    colors = [defaultdict(list) for _ in range(k)]

    def assign_color(i, j, color):
        colors[color][i].append(j)

    def check():
        for i in range(n):
            for j in range(len(colors)):
                if len(colors[j][i]) > 1:
                    return False
        return True

    def backtrack(i):
        if i == n:
            return check()

        for color in range(max_pebbles + 1):
            if not colors[color]:
                continue

            assigned = False
            for j in range(len(colors[color])):
                if len(colors[color][j]) < pebbles[i]:
                    assign_color(i, j, color)
                    if backtrack(i + 1):
                        return True
                    colors[color][j].pop()

            if not assigned:
                return False

        return False

    return backtrack(0)

if can_paint(pebbles, k):
    print("YES")
    for i in range(n):
        print(*colors[i][i])
else:
    print("NO")

