import sys
input = sys.stdin.read
data = input().split()

class Solution:
    def __init__(self):
        self.index = 0

    def read_int(self):
        val = int(data[self.index])
        self.index += 1
        return val

    def read_pair(self):
        a = self.read_int()
        b = self.read_int()
        return a, b

    def solve(self):
        t = self.read_int()
        results = []

        for _ in range(t):
            n = self.read_int()
            dishes = []

            for _ in range(n):
                a, b, m = self.read_int(), self.read_int(), self.read_int()
                dishes.append((a, b, m))

            variety = n
            for i in range(n):
                for j in range(i + 1, n):
                    if dishes[i][0] == dishes[j][0] and dishes[i][1] == dishes[j][1]:
                        variety -= 1
                        break

            results.append(variety)

            for a, b, m in dishes:
                if m == 0:
                    results.append(0, 0)
                elif m == a:
                    results.append(a, 0)
                else:
                    results.append(m, 0)

        return results

sol = Solution()
results = sol.solve()

output = "\n".join(map(str, results))
print(output)

import sys

input = sys.stdin.read
data = input().split()

index = 0
results = []

def read_test_case():
    global index
    n = int(data[index])
    index += 1
    s = data[index]
    index += 1
    return n, s

def find_partition(n, s):
    count = [0] * 2
    for char in s:
        count[int(char)] += 1

    if count[0] != count[1]:
        return -1

    zero_indices = []
    one_indices = []

    for i, char in enumerate(s):
        if char == '0':
            zero_indices.append(i + 1)
        else:
            one_indices.append(i + 1)

    if len(zero_indices) % 2 != 0 or len(one_indices) % 2 != 0:
        return -1

    half_zero = len(zero_indices) // 2
    half_one = len(one_indices) // 2

    if zero_indices[:half_zero] == one_indices[half_one:]:
        return 0, [], zero_indices[:half_zero]

    if zero_indices[half_zero:] == one_indices[:half_one]:
        return half_zero, zero_indices[half_zero:], one_indices[:half_one]

    if one_indices[:half_one] == zero_indices[half_zero:]:
        return 0, [], one_indices[:half_one]

    if one_indices[half_one:] == zero_indices[:half_zero]:
        return half_one, one_indices[half_one:], zero_indices[:half_zero]

    return -1

t = int(data[index])
index += 1

for _ in range(t):
    n, s = read_test_case()
    result = find_partition(n, s)
    results.append(result)

for result in results:
    if result == -1:
        print(-1)
    else:
