def find_clique_or_subset(n, m, k, edges):
    degrees = [0] * (n + 1)
    adj_list = [[] for _ in range(n + 1)]

    for u, v in edges:
        degrees[u] += 1
        degrees[v] += 1
        adj_list[u].append(v)
        adj_list[v].append(u)

    # Check for clique of size k
    def dfs(node, path, visited):
        if len(path) == k:
            return True
        visited[node] = True
        for neighbor in adj_list[node]:
            if not visited[neighbor]:
                if dfs(neighbor, path + [neighbor], visited):
                    return True
        visited[node] = False
        return False

    for i in range(1, n + 1):
        if dfs(i, [i], [False] * (n + 1)):
            return [2] + sorted(path)

    # Check for subset where each vertex has at least k neighbors in the subset
    for start in range(1, n + 1):
        subset = {start}
        stack = [start]
        while stack:
            node = stack.pop()
            for neighbor in adj_list[node]:
                if neighbor not in subset:
                    subset.add(neighbor)
                    stack.append(neighbor)

        if all(degrees[v] >= k for v in subset):
            return [1] + sorted(subset)

    return [-1]

