# BFS to find the maximum independent set for each component
def bfs_max_independent_set(graph):
    visited = [False] * len(graph)
    independent_set = []
    queue = deque()

    for node in range(len(graph)):
        if not visited[node]:
            visited[node] = True
            queue.append(node)
            while queue:
                current = queue.popleft()
                independent_set.append(current)
                for neighbor in graph[current]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        queue.append(neighbor)

    return independent_set

