input = sys.stdin.read
data = input().split()

n = int(data[0])
m = int(data[1])

rows = []
index = 2
for i in range(n):
    k = int(data[index])
    intervals = []
    for j in range(k):
        l = int(data[index + 2 * j])
        r = int(data[index + 2 * j + 1])
        intervals.append((l, r))
    rows.append(intervals)
    index += 2 * k

def max_quality(rows, n, m):
    cols = [0] * m
    for row in rows:
        changes = [0] * m
        for l, r in row:
            changes[l - 1] += 1
            if r < m:
                changes[r] -= 1
        for i in range(1, m):
            changes[i] += changes[i - 1]
        for i in range(m):
            cols[i] += changes[i]
    return sum(x**2 for x in cols)

print(max_quality(rows, n, m))

import sys
from math import gcd
from functools import reduce

def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    t = next(read_ints())
    results = []

    for _ in range(t):
        n, m = next(read_ints())
        right_half = list(next(read_ints()))

        adj_list = [[] for _ in range(n)]
        for _ in range(m):
            u, v = next(read_ints()) - 1, next(read_ints()) - 1
            adj_list[u].append(v)

        def dfs(node, visited):
            visited[node] = True
            for neighbor in adj_list[node]:
                if not visited[neighbor]:
                    yield from dfs(neighbor, visited)
            yield node

        def get_gcd_of_f_s():
            visited = [False] * n
            for start in range(n):
                if not visited[start]:
                    s = set(dfs(start, visited))
                    f_s = sum(right_half[i] for i in s)
                    yield f_s

        gcd_value = reduce(gcd, get_gcd_of_f_s(), 0)
        results.append(gcd_value)

    for result in results:
        print(result)

if __name__ == "__main__":
    main()

