    for _ in range(m):
        u, v = next(read_ints()) - 1, next(read_ints()) - 1
        adj_list[u].append(v)

    def get_gcd_of_f_s():
        result = 0
        visited = [False] * n

        def dfs(node):
            nonlocal result
            if visited[node]:
                return
            visited[node] = True
            for neighbor in adj_list[node]:
                result += right_values[neighbor]
                dfs(neighbor)

        for i in range(n):
